class Solution {
    public boolean[] canMakePalindromeQueries(String s, int[][] queries) {
        int n = s.length();
        int[][] diff = new int[n / 2 + 1][26];
        for (int i = 0; i < n / 2; i++) {
            for (int j = 0; j < 26; j++) {
                diff[i + 1][j] = diff[i][j];
            }
            diff[i + 1][s.charAt(i) - 'a']++;
            diff[i + 1][s.charAt(n - 1 - i) - 'a']--;
        }
        boolean[] ans = new boolean[queries.length];
        for (int i = 0; i < queries.length; i++) {
            int l1 = queries[i][0], r1 = queries[i][1], l2 = queries[i][2], r2 = queries[i][3];
            boolean valid = true;
            for (int j = 0; j < 26; j++) {
                int count = diff[r1 + 1][j] - diff[l1][j] + diff[n - l2][j] - diff[n - r2 - 1][j];
                if (count != 0) {
                    valid = false;
                    break;
                }
            }
            if (valid) {
                int pre = 0;
                for (int j = l1; j <= r1; j++) {
                    int idx = n - 1 - j;
                    if (l2 <= idx && idx <= r2) {
                        pre++;
                    }
                }
                valid = pre == r1 - l1 + 1;
            }
            ans[i] = valid;
        }
        return ans;
    }
}
